import{_ as a,o,c as r,a0 as t}from"./chunks/framework.BjpW4enL.js";const g=JSON.parse('{"title":"ADR: Payload Filtering Migration (Qdrant -&gt; Postgres)","description":"","frontmatter":{},"headers":[],"relativePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/research/T2_FILTERING_SIMPLICITY.md","filePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/research/T2_FILTERING_SIMPLICITY.md","lastUpdated":1783623176000}'),i={name:"Z_Archive/wiki_legacy/archive/legacy_pre_federation/research/T2_FILTERING_SIMPLICITY.md"};function s(n,e,d,c,l,p){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="adr-payload-filtering-migration-qdrant-gt-postgres" tabindex="-1">ADR: Payload Filtering Migration (Qdrant -&gt; Postgres) <a class="header-anchor" href="#adr-payload-filtering-migration-qdrant-gt-postgres" aria-label="Permalink to &quot;ADR: Payload Filtering Migration (Qdrant -&amp;gt; Postgres)&quot;">​</a></h1><p><strong>Status</strong>: Implementado (v3.5.1)<br><strong>Date</strong>: 2026-03-14</p><h2 id="contexto" tabindex="-1">Contexto <a class="header-anchor" href="#contexto" aria-label="Permalink to &quot;Contexto&quot;">​</a></h2><p>O filtro de extensões (<code>ext: [&quot;.rs&quot;]</code>) foi originalmente desenhado para ser aplicado via Payload Filtering na query do Qdrant (T3). No entanto, o <code>text</code> tokenizer do Qdrant quebra pontuações, criando falso-negativos (ex: <code>.py</code> virando <code>py</code>). Embora a API permita contornar isso forçando Schema Types, adicionar complexidade de schema no banco vetorial fere a separação de interesses.</p><h2 id="decisao" tabindex="-1">Decisão <a class="header-anchor" href="#decisao" aria-label="Permalink to &quot;Decisão&quot;">​</a></h2><ol><li><strong>O Qdrant (T3) volta a ser estúpido.</strong> Ele apenas recebe o vetor da pergunta, sem filtros literários, e devolve uma rede ampla (Top 30 nós) baseada exclusivamente na densidade semântica crua.</li><li><strong>O Postgres (T2) assume o poder.</strong> O Rust Coordinator passa o array de 30 UUIDs para o PostgreSQL. Na query SQL que já fazia o JOIN para recuperar os textos e cruzar o eixo Temporal (<code>before</code>), nós inserimos as cláusulas <code>LIKE</code> para as extensões (Ex: <code>fs_path LIKE &#39;%.rs&#39; OR fs_path LIKE &#39;%.py&#39;</code>).</li><li>O resultado filtrado pelo SQL tem seus scores mapeados e, então, cortado pelo <code>top_k</code> real exigido pela requisição (Limitação tardia).</li></ol><h2 id="consequencias" tabindex="-1">Consequências <a class="header-anchor" href="#consequencias" aria-label="Permalink to &quot;Consequências&quot;">​</a></h2><ul><li>Fim imediato do bug <code>No results</code> causados pelo motor de matching string do Vector DB.</li><li>Concentração da filtragem dura no banco relacional (T2), o local matematicamente correto para regex, data, versionamento e substrings.</li><li>Maior vazão no Qdrant, que não perde tempo calculando interseções textuais durante a varredura do espaço hiperdimensional.</li></ul>',8)])])}const m=a(i,[["render",s]]);export{g as __pageData,m as default};
